sys_script_include.script:
var DecisionParser = Class.create();
DecisionParser.prototype = {

    _entries: [],

    DEFAULT_PARSER: function(questions, includeDefaultAnswer = false) {
        var entries = questions.result; // array
        if (!includeDefault) entries = entries.filter(e => defaultAnswer == false);

        entries = entries.map(function(e) {
            // The question has a 'answer.valid' property, and we treat that
            // as our 'valid' for now. May override later.

            // In a few cases, answer.valid is false, such as if the 
            // referenced location has been deleted. We do not get a 
            // message saying what the problem is, so we do not set message here.
            var obj = {
                "valid": e.answer.valid,
                "location": "",
                "message": ""
            };

            // In a few cases we will set valid to false for other reasons.

            // Ex: "condition": "u_location=54^EQ",
            obj.location = e.condition == "" ? "" : e.condition.split("=")[1].split("^")[0].trim();

            // reference comes from question.answer.answerElementValues. This might be an empty array.
            if (e.answer.answerElementValues.length > 0) {
                obj['reference'] = {
                    "label": e.answer.answerElementValues[0].label,
                    "value": e.answer.answerElementValues[0].value
                };
            }
        });

        // If any object has no reference, mark it invalid
        entries
            .filter(function(e) {
                return e.valid && !Object.hasOwn(e, 'reference');
            })
            .forEach(function(e) {
                e.valid = false;
                e.message = "no valid result";
            });


        // If any entry has a blank location, mark it invalid
        entries
            .filter(function(e) {
                return e.valid && e.location.length == 0;
            })
            .forEach(function(e) {
                e.valid = false;
                e.message = "no location";
            });

        // Get all the locations, check for duplicates, mark invalid
        // any entry having one of these
        const locationCounts = {};
        const duplicateLocations = new Set();
        entries
            .filter(function(e) {
                return e.location.length > 0;
            })
            .forEach(function(e) {
				locationCounts[e.location] = (locationCounts[e.location] || 0) + 1;
            });
        for (const value of locationCounts) {
            if (locationCounts[value] > 1) {
                duplicateLocations.add(value);
            }
        }
        entries
            .filter(function(e) {
				return e.valid == true && duplicateLocations.has(e.location);
            })
			.forEach(function(e) {
				e.valid = false;
				e.message = "Duplicate location";
			});

        return entries;
    },

    Filter: {
        ALL: 0,
        VALID: 1,
        INVALID: 2
    },

    initialize: function(decision_sys_id, helper = this.DEFAULT_PARSER, includeDefault = false) {
        var dt = new sn_dt.DecisionTableAPI();
        this._entries = helper(dt.getQuestions(decision_sys_id), includeDefault);
    },

    getEntries: function(filter = Filter.VALID) {
        return this._entries.filter(function(e) {
            if (filter == Filter.ALL) return true;
            if (filter == Filter.VALID && e.valid) return true;
            if (filter == Filter.INVALID && !e.valid) return true;
            return false;
        });
    },

    // _transform: function(questions, includeDefault) {
    //     questions = questions.result;

    //     // filter out the default answer
    //     if (!includeDefault) questions = questions.filter(e => defaultAnswer == false);

    //     questions = questions.map(function(e) {

    //         // The question has a 'answer.valid' property, and we treat that
    //         // as our 'valid' for now. In a few cases we will override this.

    //         // In rare cases, answer.valid is false, such as if the 
    //         // referenced location has been deleted. We do not get a 
    //         // message saying what the problem is, so we do not set message here.
    //         var obj = {
    //             "valid": e.answer.valid,
    //             "location": "",
    //             "message": ""
    //         };

    //         // Ex: "condition": "u_location=54^EQ",
    //         obj.location = e.condition == "" ? "" : e.condition.split("=")[1].split("^")[0].trim();

    //         // reference comes from question.answer.answerElementValues. This might be an empty array.
    //         if (e.answer.answerElementValues.length > 0) {
    //             obj['reference'] = {
    //                 "label": e.answer.answerElementValues[0].label,
    //                 "value": e.answer.answerElementValues[0].value
    //             };
    //         }
    //     });

    //     return questions;
    // },

    // _validate: function(questions) {
    // 	questions = this._validateUniqueness(questions);


    // },

    // Set valid to false if he location is not unique
    // _validateUniqueness: function(questions) {


    // 	return questions;
    // },

    type: 'DecisionParser'
};
